namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast, Yogurt, Tikka spice mix, Onion, Garlic, Ginger, Tomato sauce, Heavy cream, Rice", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and simmer.\n5. Stir in cream and cooked chicken.\n6. Serve over basmati rice.", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheese, Sour cream, Taco seasoning", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 min.\n3. Warm taco shells in oven.\n4. Fill shells with beef.\n5. Top with lettuce, tomato, cheese, and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles, Shrimp, Eggs, Bean sprouts, Green onion, Peanuts, Tamarind paste, Fish sauce, Sugar, Lime", Steps = "1. Soak rice noodles in warm water 30 min.\n2. Stir-fry shrimp until pink, set aside.\n3. Scramble eggs in wok.\n4. Add drained noodles and sauce (tamarind, fish sauce, sugar).\n5. Toss with shrimp and bean sprouts.\n6. Serve with peanuts and lime.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour, Vanilla extract", Steps = "1. Preheat oven to 425°F.\n2. Melt chocolate and butter together.\n3. Whisk eggs, sugar, and vanilla.\n4. Fold in chocolate mixture and flour.\n5. Pour into greased ramekins.\n6. Bake 12-14 minutes (center should be soft).\n7. Invert onto plate and serve immediately.", AverageRating = 4.9, RatingCount = 25 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan cheese, Croutons, Caesar dressing, Lemon, Anchovy paste", Steps = "1. Wash and chop romaine lettuce.\n2. Make dressing: whisk anchovy paste, lemon juice, garlic, mustard, and olive oil.\n3. Toss lettuce with dressing.\n4. Top with shaved Parmesan and croutons.", AverageRating = 3.9, RatingCount = 6 },
    };

    private readonly List<RecipeCategory> _categories = new()
    {
        new RecipeCategory { Name = "Italian", Description = "Pasta, pizza, and Mediterranean flavors", Icon = "🍝" },
        new RecipeCategory { Name = "Indian", Description = "Spices, curries, and aromatic dishes", Icon = "🍛" },
        new RecipeCategory { Name = "Mexican", Description = "Tacos, burritos, and bold flavors", Icon = "🌮" },
        new RecipeCategory { Name = "Asian", Description = "Stir-fries, noodles, and umami", Icon = "🍜" },
        new RecipeCategory { Name = "Desserts", Description = "Sweet treats and baked goods", Icon = "🍰" },
        new RecipeCategory { Name = "Salads", Description = "Fresh, healthy, and light", Icon = "🥗" },
    };

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            var totalStars = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    <span class="rating-label">Rate this recipe:</span>
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= SelectedRating ? "selected" : "")"
                  @onclick="() => Rate(star)"
                  title="@star star(s)">★</span>
        }
    </div>
    @if (SelectedRating > 0)
    {
        <span class="rating-feedback">You rated this @SelectedRating/5 ★</span>
    }
    <div class="average-rating">
        <small>Community average: @AverageRating.ToString("F1")/5 (@RatingCount ratings)</small>
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Parameter] public EventCallback<int> OnRated { get; set; }

    private int SelectedRating;

    private async Task Rate(int stars)
    {
        SelectedRating = stars;
        await OnRated.InvokeAsync(stars);
    }
}

.star-rating {
    margin: 1.5rem 0;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.rating-label {
    font-weight: 600;
    margin-right: 0.5rem;
}

.stars {
    display: inline-flex;
    gap: 0.25rem;
    margin: 0.5rem 0;
}

.star {
    font-size: 2rem;
    cursor: pointer;
    color: #ddd;
    transition: color 0.2s, transform 0.1s;
}

.star:hover,
.star.selected {
    color: #ffc107;
    transform: scale(1.1);
}

.rating-feedback {
    display: block;
    margin-top: 0.5rem;
    color: #28a745;
    font-weight: 500;
}

.average-rating {
    margin-top: 0.5rem;
    color: #6c757d;
}

