        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

<h1>@Category Recipes</h1>

@if (Recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category yet. <a href="/submit">Be the first to add one!</a></p>
}
else
{
    <div class="row mt-3">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <div class="mb-2">
                            <span class="text-warning">@(new string('★', (int)Math.Round(recipe.AverageRating)))</span>
                            <small class="text-muted">(@recipe.AverageRating.ToString("F1")) · @recipe.RatingCount ratings</small>
                        </div>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<Recipe> Recipes { get; set; } = new();

    protected override void OnParametersSet()
    {
        var cat = System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(Category);
        Recipes = RecipeService.GetRecipesByCategory(cat);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Models
@using RecipeHub.Components.Shared

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/recipes/@Recipe.Category.ToLower()">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe. <a href="/">Browse categories</a> to find what you're looking for.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <section class="mt-4">
        <h3>🧾 Ingredients</h3>
        <ul class="list-group list-group-flush mb-4">
            @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
            {
                <li class="list-group-item">@ingredient</li>
            }
        </ul>
    </section>

    <section>
        <h3>👨‍🍳 Steps</h3>
        <div class="steps-list">
            @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step</p>
            }
        </div>
    </section>

    <StarRating RecipeId="@Recipe.Id"
                AverageRating="@Recipe.AverageRating"
                RatingCount="@Recipe.RatingCount"
                OnRated="HandleRating" />
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(Id, stars);
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services
@using RecipeHub.Models
@using Microsoft.AspNetCore.Components.Forms

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (Submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@Model.Title</strong>" with the community.</p>
        <a href="/recipe/@NewRecipeId" class="btn btn-success">View Your Recipe</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat.Name">@cat.Icon @cat.Name</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.Ingredients"
                           placeholder="One ingredient per line, or comma-separated" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="7" @bind-Value="Model.Steps"
                           placeholder="Describe each step on a new line" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary btn-lg">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel Model { get; set; } = new();
    private bool Submitted { get; set; }
    private int NewRecipeId { get; set; }

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Ingredients = Model.Ingredients,
            Steps = Model.Steps
        };
        RecipeService.AddRecipe(recipe);
        NewRecipeId = recipe.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Model = new();
        Submitted = false;
    }

    public class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100)]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = string.Empty;
    }
}

