@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Models
@using RecipeHub.Components.Shared

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/recipes/@Recipe.Category.ToLower()">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe. <a href="/">Browse categories</a> to find what you're looking for.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <section class="mt-4">
        <h3>🧾 Ingredients</h3>
        <ul class="list-group list-group-flush mb-4">
            @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
            {
                <li class="list-group-item">@ingredient</li>
            }
        </ul>
    </section>

    <section>
        <h3>👨‍🍳 Steps</h3>
        <div class="steps-list">
            @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step</p>
            }
        </div>
    </section>

    <StarRating RecipeId="@Recipe.Id"
                AverageRating="@Recipe.AverageRating"
                RatingCount="@Recipe.RatingCount"
                OnRated="HandleRating" />
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(Id, stars);
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

