else
{
    <div class="row mt-3">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <div class="mb-2">
                            <span class="text-warning">@(new string('★', (int)Math.Round(recipe.AverageRating)))</span>
                            <small class="text-muted">(@recipe.AverageRating.ToString("F1")) · @recipe.RatingCount ratings</small>
                        </div>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

